import { useRef, useState, useEffect, useCallback, forwardRef, useImperativeHandle } from 'react'
import { useVirtualizer } from '@tanstack/react-virtual'
import { Loader } from '@mantine/core'
import { usePageLoader } from '../hooks/usePageLoader'

const MIN_WIDTH = 120
const MAX_WIDTH = 480
export const DEFAULT_WIDTH = 220
export const DRAG_HANDLE_WIDTH = 4
export const ITEM_PADDING = 8
export const ITEM_GAP = 0
export const LABEL_HEIGHT = 20
// DIN A4 portrait aspect ratio (210 × 297 mm)
export const PAGE_ASPECT = 297 / 210

const DEFAULT_THUMB_HEIGHT = Math.round((DEFAULT_WIDTH - ITEM_PADDING * 2) * PAGE_ASPECT)
export const HALF_THUMB_HEIGHT = Math.round(DEFAULT_THUMB_HEIGHT / 2)

const STRIP_LABEL_HEIGHT = 28

export interface ThumbnailPanelHandle {
  scrollTo: (top: number) => void
}

interface Props {
  pdfPath: string
  pageCount: number
  selectedPage: number   // 1-indexed
  onSelectPage: (page: number) => void
  label?: string
  width?: number
  hideDragHandle?: boolean
  onWidthChange?: (width: number) => void
  onScroll?: (scrollTop: number) => void
  hideScrollbar?: boolean
  topPadding?: number
  bottomPadding?: number
  pageNumberLabel?: (index: number) => number
}

const ThumbnailPanel = forwardRef<ThumbnailPanelHandle, Props>(function ThumbnailPanel(
  { pdfPath, pageCount, selectedPage, onSelectPage, label, width: controlledWidth, hideDragHandle, onWidthChange, onScroll, hideScrollbar, topPadding = 0, bottomPadding = 0, pageNumberLabel },
  ref,
) {
  const [internalWidth, setInternalWidth] = useState(DEFAULT_WIDTH)
  const panelWidth = controlledWidth ?? internalWidth

  const thumbWidth = panelWidth - ITEM_PADDING * 2
  const thumbHeight = Math.round(thumbWidth * PAGE_ASPECT)
  const itemHeight = thumbHeight + LABEL_HEIGHT + ITEM_PADDING + ITEM_GAP

  const scrollRef = useRef<HTMLDivElement>(null)

  const virtualizer = useVirtualizer({
    count: pageCount,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => itemHeight,
    overscan: 3,
    paddingStart: topPadding,
  })

  // Re-estimate row heights when panel is resized
  useEffect(() => {
    virtualizer.measure()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [itemHeight])

  const virtualItems = virtualizer.getVirtualItems()
  const { getSrc, isLoading, load, invalidate } = usePageLoader(pdfPath, thumbWidth)

  useEffect(() => {
    for (const item of virtualItems) load(item.index + 1)
  })

  // Scroll selected page into view (e.g. after keyboard navigation)
  useEffect(() => {
    virtualizer.scrollToIndex(selectedPage - 1, { align: 'auto' })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPage])

  useImperativeHandle(ref, () => ({
    scrollTo: (top) => { if (scrollRef.current) scrollRef.current.scrollTop = top },
  }))

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'ArrowLeft' && selectedPage > 1) {
      e.preventDefault()
      onSelectPage(selectedPage - 1)
    } else if (e.key === 'ArrowRight' && selectedPage < pageCount) {
      e.preventDefault()
      onSelectPage(selectedPage + 1)
    }
  }, [selectedPage, pageCount, onSelectPage])

  const startDrag = (e: React.MouseEvent) => {
    const startX = e.clientX
    const startWidth = panelWidth
    const clamp = (w: number) => Math.max(MIN_WIDTH, Math.min(MAX_WIDTH, w))

    const onMove = (ev: MouseEvent) => {
      const w = clamp(startWidth + ev.clientX - startX)
      setInternalWidth(w)
      onWidthChange?.(w)
    }
    const onUp = (ev: MouseEvent) => {
      const w = clamp(startWidth + ev.clientX - startX)
      setInternalWidth(w)
      onWidthChange?.(w)
      invalidate()
      document.removeEventListener('mousemove', onMove)
      document.removeEventListener('mouseup', onUp)
    }
    document.addEventListener('mousemove', onMove)
    document.addEventListener('mouseup', onUp)
    e.preventDefault()
  }

  return (
    <div style={{ display: 'flex', height: '100%', flexShrink: 0 }}>
      <div style={{ display: 'flex', flexDirection: 'column', width: panelWidth, height: '100%' }}>
        {label && (
          <div
            style={{
              height: STRIP_LABEL_HEIGHT,
              flexShrink: 0,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 11,
              fontWeight: 600,
              color: 'var(--mantine-color-dimmed)',
              borderBottom: '1px solid var(--mantine-color-gray-2)',
            }}
          >
            {label}
          </div>
        )}
      <div
        ref={scrollRef}
        tabIndex={0}
        onKeyDown={handleKeyDown}
        onScroll={(e) => onScroll?.(e.currentTarget.scrollTop)}
        className={hideScrollbar ? 'hide-scrollbar' : undefined}
        style={{
          flex: 1,
          minHeight: 0,
          overflowY: 'auto',
          overflowX: 'hidden',
          outline: 'none',
          background: 'var(--mantine-color-gray-3)',
        }}
      >
        <div style={{ height: virtualizer.getTotalSize() + bottomPadding, position: 'relative' }}>
          {virtualizer.getVirtualItems().map(item => {
            const page = item.index + 1
            const src = getSrc(page)
            const isSelected = page === selectedPage

            return (
              <div
                key={item.key}
                style={{
                  position: 'absolute',
                  top: item.start,
                  left: 0,
                  width: '100%',
                  height: item.size,
                  padding: ITEM_PADDING,
                  paddingBottom: 0,
                  boxSizing: 'border-box',
                  cursor: 'pointer',
                }}
                onClick={() => onSelectPage(page)}
              >
                <div
                  style={{
                    border: `2px solid ${isSelected ? 'var(--mantine-color-blue-5)' : 'transparent'}`,
                    borderRadius: 4,
                    overflow: 'hidden',
                    background: 'var(--mantine-color-gray-1)',
                  }}
                >
                  {src ? (
                    <img
                      src={src}
                      alt={`Page ${page}`}
                      style={{ width: '100%', display: 'block' }}
                      draggable={false}
                    />
                  ) : (
                    <div
                      style={{
                        width: '100%',
                        height: thumbHeight,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                      }}
                    >
                      {isLoading(page) && <Loader size="xs" />}
                    </div>
                  )}
                </div>
                <div
                  style={{
                    textAlign: 'center',
                    fontSize: 11,
                    color: 'var(--mantine-color-gray-7)',
                    height: LABEL_HEIGHT,
                    lineHeight: `${LABEL_HEIGHT}px`,
                  }}
                >
                  {pageNumberLabel ? pageNumberLabel(item.index) : page}
                </div>
              </div>
            )
          })}
        </div>
      </div>
      </div>

      {/* Resize drag handle */}
      {!hideDragHandle && (
        <div
          onMouseDown={startDrag}
          style={{
            width: 4,
            height: '100%',
            cursor: 'col-resize',
            flexShrink: 0,
            background: 'var(--mantine-color-gray-3)',
          }}
        />
      )}
    </div>
  )
})

export default ThumbnailPanel

import { useRef, useState } from 'react'
import { Box, Button, Center, Group, SegmentedControl, Text } from '@mantine/core'
import { notifications } from '@mantine/notifications'
import { MergePDFs, OpenPDF, PageCount, SavePDF } from '../../wailsjs/go/main/App'
import ThumbnailPanel, {
  DEFAULT_WIDTH, DRAG_HANDLE_WIDTH, HALF_THUMB_HEIGHT,
  ITEM_PADDING, ITEM_GAP, LABEL_HEIGHT, PAGE_ASPECT,
  ThumbnailPanelHandle,
} from './ThumbnailPanel'

// Maps a panel's 0-based page index to its output PDF page number.
// isFirst: true if this panel's pages go first in the interleave (odd output pages).
// countOther: page count of the other panel.
function makePageNumberLabel(isFirst: boolean, countOther: number) {
  const minCount = countOther  // interleaved section length = min(count, countOther), but we only know countOther here
  return (index: number) => {
    const n = index + 1  // 1-based
    if (n <= minCount) {
      return isFirst ? 2 * n - 1 : 2 * n
    }
    // extra pages appended after interleave
    return 2 * minCount + (n - minCount)
  }
}

function itemHeight(panelWidth: number) {
  const thumbWidth = panelWidth - ITEM_PADDING * 2
  const thumbHeight = Math.round(thumbWidth * PAGE_ASPECT)
  return thumbHeight + LABEL_HEIGHT + ITEM_PADDING + ITEM_GAP
}

function basename(p: string) {
  return p.split(/[\\/]/).pop() ?? p
}

type FirstPageIn = 'a' | 'b'

export default function MergeMode() {
  const [pathA, setPathA] = useState<string | null>(null)
  const [countA, setCountA] = useState(0)
  const [pathB, setPathB] = useState<string | null>(null)
  const [countB, setCountB] = useState(0)
  const [pageA, setPageA] = useState(1)
  const [pageB, setPageB] = useState(1)
  const [firstPageIn, setFirstPageIn] = useState<FirstPageIn>('a')
  const [sharedWidth, setSharedWidth] = useState(DEFAULT_WIDTH)
  const [merging, setMerging] = useState(false)
  const refA = useRef<ThumbnailPanelHandle>(null)
  const refB = useRef<ThumbnailPanelHandle>(null)
  const syncing = useRef(false)

  const handleScrollA = (top: number) => {
    if (syncing.current) return
    syncing.current = true
    refB.current?.scrollTo(top)
    syncing.current = false
  }

  const handleScrollB = (top: number) => {
    if (syncing.current) return
    syncing.current = true
    refA.current?.scrollTo(top)
    syncing.current = false
  }

  const handleChooseA = async () => {
    const p = await OpenPDF()
    if (!p) return
    const count = await PageCount(p)
    setPathA(p)
    setCountA(count)
    setPageA(1)
  }

  const handleChooseB = async () => {
    const p = await OpenPDF()
    if (!p) return
    const count = await PageCount(p)
    setPathB(p)
    setCountB(count)
    setPageB(1)
  }

  const handleMerge = async () => {
    if (!pathA || !pathB) return
    const outPath = await SavePDF()
    if (!outPath) return
    setMerging(true)
    try {
      const effectiveFirst = firstPageIn === 'a' ? pathA : pathB
      const effectiveSecond = firstPageIn === 'a' ? pathB : pathA
      await MergePDFs(effectiveFirst, effectiveSecond, outPath, false)
      notifications.show({ message: `Saved to ${outPath}`, color: 'green' })
    } catch (e) {
      notifications.show({ title: 'Merge failed', message: String(e), color: 'red' })
    } finally {
      setMerging(false)
    }
  }

  const bothLoaded = pathA !== null && pathB !== null

  // Offsets only apply once both files are loaded (they describe interleave order).
  const topPaddingA = bothLoaded && firstPageIn === 'b' ? HALF_THUMB_HEIGHT : 0
  const topPaddingB = bothLoaded && firstPageIn === 'a' ? HALF_THUMB_HEIGHT : 0

  // Equalise the maximum scrollTop of both strips.
  // maxScroll_first  = countFirst  * ihFirst  + 0             - H
  // maxScroll_second = countSecond * ihSecond + HALF_THUMB_HEIGHT - H
  // diff = maxScroll_second - maxScroll_first
  // bottomPadding_first  = max(0,  diff)
  // bottomPadding_second = max(0, -diff)
  const ih = itemHeight(sharedWidth)
  const [countFirst, ihFirst, countSecond, ihSecond] = firstPageIn === 'a'
    ? [countA, ih, countB, ih]
    : [countB, ih, countA, ih]
  const diff = countSecond * ihSecond - countFirst * ihFirst + HALF_THUMB_HEIGHT
  const bottomPaddingFirst  = Math.max(0,  diff)
  const bottomPaddingSecond = Math.max(0, -diff)
  const bottomPaddingA = firstPageIn === 'a' ? bottomPaddingFirst : bottomPaddingSecond
  const bottomPaddingB = firstPageIn === 'a' ? bottomPaddingSecond : bottomPaddingFirst

  const aIsFirst = firstPageIn === 'a'
  const pageLabelA = bothLoaded ? makePageNumberLabel(aIsFirst,  aIsFirst ? countB : countA) : undefined
  const pageLabelB = bothLoaded ? makePageNumberLabel(!aIsFirst, aIsFirst ? countA : countB) : undefined

  // A has no drag handle; B has one — toolbar columns match accordingly
  const colWidthA = sharedWidth
  const colWidthB = sharedWidth + DRAG_HANDLE_WIDTH

  return (
    <Box style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      {/* Toolbar: columns A and B aligned with their strips, then controls on the right */}
      <Box
        style={{
          flexShrink: 0,
          borderBottom: '1px solid var(--mantine-color-gray-3)',
          display: 'flex',
          alignItems: 'stretch',
        }}
      >
        <FilePickerColumn
          label="File A"
          path={pathA}
          width={colWidthA}
          onChoose={handleChooseA}
        />
        <FilePickerColumn
          label="File B"
          path={pathB}
          width={colWidthB}
          onChoose={handleChooseB}
        />
        <Group gap={12} px={12} style={{ flex: 1, justifyContent: 'flex-end' }}>
          <Group gap={8}>
            <Text size="sm" c="dimmed">First page in</Text>
            <SegmentedControl
              size="xs"
              value={firstPageIn}
              onChange={(v) => setFirstPageIn(v as FirstPageIn)}
              data={[
                { label: 'File A', value: 'a' },
                { label: 'File B', value: 'b' },
              ]}
            />
          </Group>
          <Button size="sm" disabled={!bothLoaded} loading={merging} onClick={handleMerge}>
            Merge & Save
          </Button>
        </Group>
      </Box>

      <Box style={{ flex: 1, overflow: 'hidden', display: 'flex' }}>
        {pathA && (
          <ThumbnailPanel
            ref={refA}
            pdfPath={pathA}
            pageCount={countA}
            selectedPage={pageA}
            onSelectPage={setPageA}
            width={sharedWidth}
            hideDragHandle
            onScroll={handleScrollA}
            hideScrollbar
            topPadding={topPaddingA}
            bottomPadding={bottomPaddingA}
            pageNumberLabel={pageLabelA}
          />
        )}
        {pathB && (
          <ThumbnailPanel
            ref={refB}
            pdfPath={pathB}
            pageCount={countB}
            selectedPage={pageB}
            onSelectPage={setPageB}
            width={sharedWidth}
            onWidthChange={setSharedWidth}
            onScroll={handleScrollB}
            topPadding={topPaddingB}
            bottomPadding={bottomPaddingB}
            pageNumberLabel={pageLabelB}
          />
        )}
        {!pathA && !pathB && (
          <Center style={{ flex: 1 }}>
            <Text c="dimmed" size="sm">Choose PDF files above to begin</Text>
          </Center>
        )}
      </Box>
    </Box>
  )
}


function FilePickerColumn({
  label,
  path,
  width,
  onChoose,
}: {
  label: string
  path: string | null
  width: number
  onChoose: () => void
}) {
  return (
    <Box
      style={{
        width,
        flexShrink: 0,
        padding: '6px 8px',
        borderRight: '1px solid var(--mantine-color-gray-3)',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        gap: 2,
      }}
    >
      <Group justify="space-between" gap={4} wrap="nowrap">
        <Text size="xs" c="dimmed">{label}</Text>
        <Button size="xs" variant="default" onClick={onChoose}>Choose…</Button>
      </Group>
      <Text
        size="xs"
        style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
        title={path ?? undefined}
      >
        {path ? basename(path) : '—'}
      </Text>
    </Box>
  )
}

import { useState } from 'react'
import { Box, Button, Center } from '@mantine/core'
import ThumbnailPanel from './ThumbnailPanel'
import DetailPanel from './DetailPanel'
import { OpenPDF, PageCount } from '../../wailsjs/go/main/App'

export default function SplitMode() {
  const [pdfPath, setPdfPath] = useState<string | null>(null)
  const [pageCount, setPageCount] = useState(0)
  const [selectedPage, setSelectedPage] = useState(1)

  const handleOpen = async () => {
    const path = await OpenPDF()
    if (!path) return
    const count = await PageCount(path)
    setPdfPath(path)
    setPageCount(count)
    setSelectedPage(1)
  }

  return (
    <Box style={{ display: 'flex', height: '100%' }}>
      {pdfPath ? (
        <ThumbnailPanel
          pdfPath={pdfPath}
          pageCount={pageCount}
          selectedPage={selectedPage}
          onSelectPage={setSelectedPage}
        />
      ) : null}

      {pdfPath ? (
        <DetailPanel
          pdfPath={pdfPath}
          pageNum={selectedPage}
          pageCount={pageCount}
          onNavigate={setSelectedPage}
        />
      ) : (
        <Box style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Center>
            <Button onClick={handleOpen}>Open PDF</Button>
          </Center>
        </Box>
      )}
    </Box>
  )
}

import { useRef, useState, useEffect } from 'react'
import { RenderPage } from '../../wailsjs/go/main/App'

interface PageLoader {
  getSrc: (page: number) => string | undefined
  isLoading: (page: number) => boolean
  isFailed: (page: number) => boolean
  load: (page: number) => void
  invalidate: () => void
}

export function usePageLoader(pdfPath: string, widthPx: number): PageLoader {
  const cacheRef = useRef(new Map<number, string>())
  const loadingRef = useRef(new Set<number>())
  const failedRef = useRef(new Set<number>())
  const [, setTick] = useState(0)

  const invalidate = () => {
    cacheRef.current.clear()
    loadingRef.current.clear()
    failedRef.current.clear()
    setTick(t => t + 1)
  }

  useEffect(() => {
    invalidate()
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pdfPath])

  const load = (page: number) => {
    if (cacheRef.current.has(page) || loadingRef.current.has(page) || failedRef.current.has(page)) return
    loadingRef.current.add(page)
    RenderPage(pdfPath, page, widthPx)
      .then((b64: string) => {
        cacheRef.current.set(page, `data:image/png;base64,${b64}`)
        loadingRef.current.delete(page)
        setTick(t => t + 1)
      })
      .catch((err: unknown) => {
        console.error(`RenderPage failed for page ${page}:`, err)
        loadingRef.current.delete(page)
        failedRef.current.add(page)
        setTick(t => t + 1)
      })
  }

  return {
    getSrc: (page) => cacheRef.current.get(page),
    isLoading: (page) => loadingRef.current.has(page),
    isFailed: (page) => failedRef.current.has(page),
    load,
    invalidate,
  }
}

